// Inaya's Birthday Counter
// Born: August 5, 2025 at 1:50am ET (America/New_York)

function nowInNY() {
    const now = new Date();
    const parts = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York',
        year: 'numeric', month: '2-digit', day: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: false
    }).formatToParts(now);
    const get = (type) => parseInt(parts.find(p => p.type === type).value);
    return { year: get('year'), month: get('month'), day: get('day'),
             hour: get('hour'), minute: get('minute'), second: get('second') };
}

function nyToUTC(year, month, day, hour, minute, second = 0) {
    const pad = n => String(n).padStart(2, '0');
    const iso = `${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:${pad(second)}`;
    for (const off of ['-05:00', '-04:00']) {
        const c = new Date(iso + off);
        const p = new Intl.DateTimeFormat('en-US', {
            timeZone: 'America/New_York',
            year:'numeric',month:'2-digit',day:'2-digit',
            hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false
        }).formatToParts(c);
        const g = t => parseInt(p.find(x => x.type === t).value);
        if (g('year')===year && g('month')===month && g('day')===day &&
            g('hour')===hour && g('minute')===minute) return c;
    }
    return new Date(iso + '-05:00');
}

const birthDate = nyToUTC(2025, 8, 5, 1, 50, 0);

function getMonthsElapsed(ny) {
    let m = (ny.year - 2025) * 12 + (ny.month - 8);
    if (ny.day < 5 || (ny.day === 5 && (ny.hour < 1 || (ny.hour === 1 && ny.minute < 50)))) m--;
    return Math.max(0, m);
}

function getMonthlyBday(n) {
    let m = 8 + n, y = 2025 + Math.floor((m-1)/12);
    m = ((m-1)%12)+1;
    return nyToUTC(y, m, 5, 1, 50, 0);
}

function getNextAnnualBirthday(ny) {
    let y = ny.year;
    if (new Date() >= nyToUTC(y, 8, 5, 1, 50, 0)) y++;
    return nyToUTC(y, 8, 5, 1, 50, 0);
}

function formatCountdown(ms) {
    if (ms <= 0) return '0h 0m 0s';
    const s = Math.floor(ms/1000);
    const d = Math.floor(s/86400), h = Math.floor((s%86400)/3600),
          m = Math.floor((s%3600)/60), sc = s%60;
    return d > 0 ? `${d}d ${h}h ${m}m ${sc}s` : `${h}h ${m}m ${sc}s`;
}

function ordinal(n) {
    const s = ['th','st','nd','rd'], v = n%100;
    return n + (s[(v-20)%10] || s[v] || s[0]);
}

function updateCounters() {
    const now = new Date(), ny = nowInNY(), diff = now - birthDate;
    if (diff < 0) return;
    const days = Math.floor(diff / 86400000);
    document.getElementById('days-counter').textContent = days.toLocaleString();
    const wk = Math.floor(days/7), wd = days%7;
    document.getElementById('weeks-counter').textContent = `${wk} week${wk!==1?'s':''} ${wd} day${wd!==1?'s':''}`;
    const mo = getMonthsElapsed(ny);
    const lastBday = getMonthlyBday(mo);
    const dSince = Math.floor((now - lastBday) / 86400000);
    document.getElementById('months-counter').textContent = `${mo} month${mo!==1?'s':''} ${dSince} day${dSince!==1?'s':''}`;
    document.getElementById('monthly-bday-counter').textContent = `${ordinal(mo)} month old! ✦`;
    const next = getMonthlyBday(mo+1), msLeft = next - now;
    document.getElementById('timer-counter').textContent = formatCountdown(msLeft) + ` until ${ordinal(mo+1)} month`;
    const pct = Math.min(100, Math.max(0, ((now - lastBday)/(next - lastBday))*100));
    document.getElementById('progress-bar-fill').style.width = pct.toFixed(2) + '%';
    const ann = getNextAnnualBirthday(ny);
    const dAnn = Math.floor((ann - now)/86400000);
    document.getElementById('progress-label').textContent = `${dAnn}d until ${ann.getFullYear()} bday · ${pct.toFixed(0)}% done`;
}

