// Auto-calculate Inaya's exact age at time of travel
function ageAtDate(dateStr) {
    const travel = new Date(dateStr + 'T12:00:00');
    const birth  = new Date('2025-08-05T01:50:00');
    if (travel <= birth) return 'Born here';

    let years  = travel.getFullYear() - birth.getFullYear();
    let months = travel.getMonth()    - birth.getMonth();
    let days   = travel.getDate()     - birth.getDate();

    if (days < 0) {
        months--;
        const prevMonth = new Date(travel.getFullYear(), travel.getMonth(), 0);
        days += prevMonth.getDate();
    }
    if (months < 0) { years--; months += 12; }

    const parts = [];
    if (years  > 0) parts.push(`${years} yr${years  !== 1 ? 's' : ''}`);
    if (months > 0) parts.push(`${months} month${months !== 1 ? 's' : ''}`);
    if (days   > 0 && years === 0) parts.push(`${days} day${days !== 1 ? 's' : ''}`);
    return parts.join(' ') + ' old';
}

function formatTravelDate(dateStr) {
    const d = new Date(dateStr + 'T12:00:00');
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function renderCountriesSummary() {
    const n = countriesVisited.length;
    document.getElementById('countries-flags').textContent = countriesVisited.map(c => c.flag).join(' ');
    document.getElementById('countries-count').textContent = `${n} countr${n===1?'y':'ies'} visited`;
}

function renderOverlay() {
    const n = countriesVisited.length;
    document.getElementById('overlay-subtitle').textContent =
        `${n} countr${n===1?'y':'ies'} · ${countriesVisited.map(c=>c.flag).join(' ')}`;

    document.getElementById('overlay-list').innerHTML = countriesVisited.map((c, i) => `
        <div class="overlay-item">
            ${c.photo
                ? `<img src="${c.photo}" class="overlay-photo" alt="${c.name}" />`
                : `<div class="overlay-photo overlay-photo--placeholder">${c.flag}</div>`}
            <div class="overlay-info">
                <div class="overlay-item-top">
                    <span class="overlay-flag">${c.flag}</span>
                    <span class="overlay-name">${c.name}</span>
                </div>
                <span class="overlay-note">${c.note}</span>
                <span class="overlay-age">${ageAtDate(c.travelDate)}</span>
                <span class="overlay-date">✈ ${formatTravelDate(c.travelDate)}</span>
            </div>
            ${c.timeCapsule ? `<button class="capsule-btn" onclick="openCapsule(${i})">📖</button>` : ''}
        </div>
    `).join('');
}

function openOverlay() {
    const overlay = document.getElementById('countries-overlay');
    overlay.classList.add('active');
}

function closeOverlay() {
    const overlay = document.getElementById('countries-overlay');
    overlay.classList.remove('active');
}

function initCountries() {
    renderCountriesSummary();
    renderOverlay();
    // Ensure overlay is fully hidden on load
    const overlay = document.getElementById('countries-overlay');
    overlay.classList.remove('active');

    document.getElementById('countries-card').addEventListener('click', openOverlay);
    document.getElementById('overlay-close').addEventListener('click', e => { e.stopPropagation(); closeOverlay(); });
    overlay.addEventListener('click', e => {
        if (e.target === overlay) closeOverlay();
    });
}

document.addEventListener('DOMContentLoaded', () => {
    updateCounters();
    setInterval(updateCounters, 1000);
    initCountries();
});

// ── Time Capsule Modal ─────────────────────────────────────────────────────
function openCapsule(index) {
    const c = countriesVisited[index];
    if (!c || !c.timeCapsule) return;
    const tc = c.timeCapsule;

    const buildSection = (section, label, icon) => `
        <div class="capsule-section">
            <div class="capsule-section-header">
                <span class="capsule-section-icon">${icon}</span>
                <div>
                    <div class="capsule-section-label">${label}</div>
                    <div class="capsule-section-city">${section.city}</div>
                </div>
            </div>
            <div class="capsule-weather">🌡 ${section.weather}</div>
            <div class="capsule-moments">
                <div class="capsule-moment-group good">
                    <div class="capsule-moment-title">✦ Highlights</div>
                    ${section.good.map(g => `<div class="capsule-moment-item">${g}</div>`).join('')}
                </div>
                <div class="capsule-moment-group bad">
                    <div class="capsule-moment-title">↓ In The News</div>
                    ${section.bad.map(b => `<div class="capsule-moment-item">${b}</div>`).join('')}
                </div>
            </div>
        </div>
    `;

    document.getElementById('capsule-title').textContent = `${c.flag} ${c.name} · ${formatTravelDate(c.travelDate)}`;
    document.getElementById('capsule-age').textContent = `Inaya was ${ageAtDate(c.travelDate)}`;
    document.getElementById('capsule-body').innerHTML =
        buildSection(tc.departure, 'Leaving Home', '🛫') +
        buildSection(tc.arrival, 'Arriving', '🛬');

    document.getElementById('capsule-overlay').classList.add('active');
}

function closeCapsule() {
    document.getElementById('capsule-overlay').classList.remove('active');
}

document.addEventListener('DOMContentLoaded', () => {
    document.getElementById('capsule-close').addEventListener('click', closeCapsule);
    document.getElementById('capsule-overlay').addEventListener('click', e => {
        if (e.target === document.getElementById('capsule-overlay')) closeCapsule();
    });
});
